it("should quote 5 G for an empty item list (processing fee only)", () => {
  const scenario = {
    customer: { yearsWithMHPCO: 0 },
    steps: [{ op: "quote", items: [] }],
  };
  const { results } = runScenario(scenario);
  expect(results).toEqual([{ premium: 5 }]);
});

